esqlQuery.esql:
// Alert when the OpenTelemetry Collector reports non-zero rate of failed metric point exports.
//
// metrics.otelcol_exporter_send_failed_metric_points is a cumulative counter; RATE() yields
// per-bucket increases. TS is used for time-series metrics (counter resets handled by the TS pipeline).
//
// Scope: metrics-collectortelemetry* and collectortelemetry.otel dataset to avoid mixing with
// unrelated metrics-* streams.
//
// Grouping: service.name and service.instance.id help identify which collector instance fails.
//
// Tuning: raise the threshold (e.g. failed_metric_points_rate > N) or increase alert delay
// to reduce noise from brief blips.
//
TS metrics-collectortelemetry*
| WHERE data_stream.dataset == "collectortelemetry.otel"
| STATS failed_metric_points_rate = SUM(RATE(metrics.otelcol_exporter_send_failed_metric_points)) BY service.name, service.instance.id
| WHERE failed_metric_points_rate > 0
| SORT failed_metric_points_rate DESC
